ps.pstext:
if !HaveSVE2FP8DOT4() then EndOfDecode(Decode_UNDEF); end;
let n : integer = UInt(Zn);
let m : integer = UInt(Zm);
let da : integer = UInt(Zda);
let index : integer = UInt(i2);

CheckFPMREnabled();
if IsFeatureImplemented(FEAT_SSVE_FP8DOT4) && IsFeatureImplemented(FEAT_FP8DOT4) then
    CheckSVEEnabled();
elsif IsFeatureImplemented(FEAT_FP8DOT4) then
    CheckNonStreamingSVEEnabled();
else
    CheckStreamingSVEEnabled();
end;
let VL : integer{} = CurrentVL();
let elements : integer = VL DIV 32;
let eltspersegment : integer = 128 DIV 32;
let operand1 : bits(VL) = Z{}(n);
let operand2 : bits(VL) = Z{}(m);
let operand3 : bits(VL) = Z{}(da);
var result : bits(VL);

for e = 0 to elements-1 do
    let segmentbase : integer = e - (e MOD eltspersegment);
    let s : integer = segmentbase + index;
    let op1 : bits(32) = operand1[e*:(32)];
    let op2 : bits(32) = operand2[s*:(32)];
    var sum : bits(32)  = operand3[e*:(32)];

    sum = FP8DotAddFP{32, 32}(sum, op1, op2, FPCR(), FPMR());
    result[e*:(32)] = sum;
end;

Z{VL}(da) = result;
